<?php defined('ABSPATH') || exit; class FounderKit_REST_API { private static ?FounderKit_REST_API $instance=null; public static function instance(): self { if(!self::$instance) self::$instance=new self(); return self::$instance; } public function __construct(){ add_action('rest_api_init',[$this,'register_routes']); } public function register_routes(): void { if(!(new FounderKit_Settings())->get('enable_rest_api')) return; register_rest_route('founderkit/v1','/settings',['methods'=>'GET','permission_callback'=>fn()=>current_user_can('manage_founderkit'),'callback'=>fn()=>rest_ensure_response((new FounderKit_Settings())->all())]); } }
